import{j as o,b as l,c as e,aa as r}from"./chunks/framework.Bxf40uRC.js";const p=JSON.parse('{"title":"日志","description":"","frontmatter":{},"headers":[],"relativePath":"Mysql/日志.md","filePath":"Mysql/日志.md","lastUpdated":null}'),i={name:"Mysql/日志.md"},a=r('<h1 id="日志" tabindex="-1">日志 <a class="header-anchor" href="#日志" aria-label="Permalink to &quot;日志&quot;">​</a></h1><ol><li><strong>undo log（回滚日志）</strong>：是 Innodb 存储引擎层生成的日志，实现了事务中的<strong>原子性</strong>，主要<strong>用于事务回滚和 MVCC</strong>。</li><li><strong>redo log（重做日志）</strong>：是 Innodb 存储引擎层生成的日志，实现了事务中的<strong>持久性</strong>，主要<strong>用于掉电等故障恢复</strong>；</li><li><strong>binlog （归档日志）</strong>：是 Server 层生成的日志，主要<strong>用于数据备份和主从复制</strong>；</li></ol><h2 id="什么是buffer-pool" tabindex="-1">什么是Buffer Pool? <a class="header-anchor" href="#什么是buffer-pool" aria-label="Permalink to &quot;什么是Buffer Pool?&quot;">​</a></h2><p>mysql的数据都是存储在磁盘中的，当我们要更新一条记录的时候，得先从磁盘读取该记录，然后在内存中修改这条记录，为了下次更加方便的读取，可以先存到缓存中，<strong>因此这就是buffer pool存在的意义</strong>；</p><h3 id="存放的信息" tabindex="-1">存放的信息 <a class="header-anchor" href="#存放的信息" aria-label="Permalink to &quot;存放的信息&quot;">​</a></h3><ol><li>数据页</li><li>索引页</li><li>undo页</li><li>锁信息</li></ol><blockquote><p>为什么存放undo页？</p></blockquote><p>很好理解，事务开始之后，innodb更新记录之前，首先要记录相应的undo log，这条undo log就会被放入buffer pool中；</p><h3 id="tips" tabindex="-1">tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;tips&quot;">​</a></h3><ol><li>buffer pool是innodb层拥有的东西；</li></ol><h2 id="什么是undo-log" tabindex="-1">什么是undo log？ <a class="header-anchor" href="#什么是undo-log" aria-label="Permalink to &quot;什么是undo log？&quot;">​</a></h2><p>innodb层为了保证事务的原子性，生成的日志，主要用于事务回滚和MVCC；</p><h2 id="什么是redo-log" tabindex="-1">什么是redo log？ <a class="header-anchor" href="#什么是redo-log" aria-label="Permalink to &quot;什么是redo log？&quot;">​</a></h2><p><strong>redo log</strong>(重做日志)：记录了某个数据页做了什么修改，比如<strong>对 XXX 表空间中的 YYY 数据页 ZZZ 偏移量的地方做了AAA 更新</strong>；</p><p><strong>WAL</strong>技术：mysql的写操作不是直接写在磁盘上，而是先写日志，然后在合适的时机再写到磁盘上；</p><img src="https://s2.loli.net/2024/04/17/MEK6eogrfUbnGd2.png" alt="image-20240417152939706" style="zoom:80%;"><blockquote><p>undo log 和redo log的区别？</p></blockquote><ul><li>undo log记录此次事务完成前的状态，用来事务回滚，保证原子性；</li><li>redo log记录此次事务的数据更新后的值，用来保证事务的持久性；</li></ul><h3 id="redo-log的产生过程" tabindex="-1">redo log的产生过程 <a class="header-anchor" href="#redo-log的产生过程" aria-label="Permalink to &quot;redo log的产生过程&quot;">​</a></h3><ol><li>对于数据的修改产生的redo log，先会翻入redo log buffer中； <ul><li>redo log buffer默认16MB，通过innodb_log_buffer_size参数调整大小；</li></ul></li><li>通过innodb_flush_log_at_trx_commit参数控制刷盘时机； <ul><li>0：redo log留在redo log buffer中，提交事务不会触发写入磁盘的操作； <ul><li>innodb后台线程每一秒，通过write()将redo log buffer中的redo log写入到page cache中，然后调用fsync()将其写到磁盘中；</li></ul></li><li>1：在每次事务提交的时候，将缓存在redo log buffer中的redo log直接持久化到磁盘中；</li><li>2：每次事务提交的时候，将redo log buffer的redo log写到redo log 文件中，即page cache中； <ul><li>innodb后台线程每一秒，通过fsync()将page cache中的内存同步到磁盘中；</li><li>相比与0，如过mysql崩溃，前一秒的内容就丢失了，但是2，只有当操作系统崩溃才可能丢失数据；</li></ul></li></ul></li></ol><h2 id="什么是bin-log" tabindex="-1">什么是bin log？ <a class="header-anchor" href="#什么是bin-log" aria-label="Permalink to &quot;什么是bin log？&quot;">​</a></h2><p>MySql在完成一条更新操作之后，Server层还会生成一条binlog，等之后事务提交的时候，会将该事务执行过程中产生的binlog统一写入binlog文件中；</p><blockquote><p>为什么有了binlog，还需要redo log？</p></blockquote><ol><li>binlog记录的是server层的操作记录，不具有crash-safe能力；binlog只能用于归档操作；</li><li>需要靠redo log来保证数据的持久性；</li></ol><p>区别：</p><ol><li>文件格式不同：binlog有多种格式类型，但是redo log是物理日志；</li><li>写入方式不同：binlog保留的是全量日志，追加写；redo log是循环写；</li><li>用途不同：binlog用于主从复制，redo log用于持久性，掉电的故障恢复；</li><li>适用对象：binlog是server层日志，redo log是innodb存储引擎实现的日志；</li></ol><h3 id="bin-log的产生过程" tabindex="-1">bin log的产生过程 <a class="header-anchor" href="#bin-log的产生过程" aria-label="Permalink to &quot;bin log的产生过程&quot;">​</a></h3><ol><li>事务执行过程中，先把日志写到binlog cache中；</li><li>事务提交后，把binlog cache写到binlog 文件中，write()写入page cache，然后fsync()同步到磁盘；</li></ol><h2 id="什么是两阶段提交" tabindex="-1">什么是两阶段提交？ <a class="header-anchor" href="#什么是两阶段提交" aria-label="Permalink to &quot;什么是两阶段提交？&quot;">​</a></h2><p>问题：</p><ol><li><strong>如果将redo log刷盘之后，mysql宕机了，此时binlog还没同步</strong>，mysql重启之后，可以通过redo log恢复该字段的信息，但是binlog没有记录，<strong>造成主从不一致</strong>；</li><li>如<strong>果bin log刷盘，mysql宕机，redo log没有来及写入</strong>，崩溃恢复后，这个事务无效，回滚了，但是binlog中存在，<strong>仍然会造成主从不一致</strong>；</li></ol><h3 id="过程" tabindex="-1">过程 <a class="header-anchor" href="#过程" aria-label="Permalink to &quot;过程&quot;">​</a></h3><ol><li><strong>prepare阶段</strong>：将**XID(内部XA事务的ID)**写入到redo log中，同时将redo log 对应的事务状态设置为prepare，然后将redo log持久化到磁盘；</li><li><strong>commit阶段</strong>：将XID写入到binlog，然后将binlog持久化到磁盘中，接着调用引擎的提交事务的接口，将redo log设置为commit，该状态不需要持久到磁盘中，只需要write到page cache中即可；</li></ol><h3 id="异常情况" tabindex="-1">异常情况 <a class="header-anchor" href="#异常情况" aria-label="Permalink to &quot;异常情况&quot;">​</a></h3><ol><li>如果在prepare阶段，mysql崩了； <ul><li>此时redo log已经持久化到了磁盘，具有XID，当重启之后，会查找redo log中为prepare状态的XID，然后在binlog中查找是否也存在； <ul><li>不存在，事务回滚，不用担心数据不一致的情况；</li></ul></li></ul></li><li>如果在commit阶段，mysql重启； <ul><li>此时redo log已经持久化到了磁盘，具有XID，binlog也已经持久化到了磁盘，说明事务执行成功了，则提交事务即可；</li></ul></li></ol>',35),n=[a];function t(g,d,s,b,u,h){return l(),e("div",null,n)}const f=o(i,[["render",t]]);export{p as __pageData,f as default};
